//予約
import { NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

export async function POST(request: Request) {
    try {
        const body = await request.json();
        const { therapistId, date, price } = body;

        // 1. バリデーション
        if (!therapistId || !date || !price) {
            return NextResponse.json({ error: "入力項目が足りません" }, { status: 400 });
        }

        const userId = "user_1"; // テスト用固定ユーザーID
        const bookingDate = new Date(date);

        // 2. 重複チェック（同じセラピストに同じ時間の予約がないか確認）
        const conflict = await prisma.reservation.findFirst({
            where: {
                therapistId: therapistId,
                date: bookingDate,
            }
        });

        if (conflict) {
            return NextResponse.json({ error: "その時間は既に予約されています" }, { status: 400 });
        }

        // 3. DBに保存
        const reservation = await prisma.reservation.create({
            data: {
                userId: userId,
                therapistId: therapistId,
                date: bookingDate,
                price: Number(price),
                status: "PENDING",
            },
        });

        return NextResponse.json({ message: "予約完了！", reservation }, { status: 201 });

    } catch (error) {
        console.error("予約保存エラー:", error);
        return NextResponse.json({ error: "予約に失敗しました" }, { status: 500 });
    }
}